  "inlineSchema": "// ============================================================\n// Football Field Reservation System — Prisma Schema (draft v1)\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ---------------------------\n// Enums\n// ---------------------------\n\nenum UserRole {\n  ADMIN\n  USER\n}\n\nenum BookingStatus {\n  PENDING // waiting for admin approval\n  CONFIRMED // approved / auto-confirmed / admin-created\n  REJECTED // admin rejected the request\n  CANCELLED // admin cancelled an already-confirmed booking\n}\n\nenum BookingSource {\n  ONLINE_DIRECT // created by a trusted user, auto-confirmed\n  ONLINE_REQUEST // created by a non-trusted user, needs approval\n  ADMIN_PHONE // admin created it on behalf of a phone caller (registered or guest)\n}\n\nenum RecurrenceFrequency {\n  WEEKLY\n}\n\n// ---------------------------\n// User\n// ---------------------------\n\nmodel User {\n  id              String   @id @default(cuid())\n  email           String   @unique\n  passwordHash    String\n  phone           String   @unique // mandatory at registration\n  teamName        String? // optional\n  role            UserRole @default(USER)\n  canBookDirectly Boolean  @default(false) // admin-controlled: true = auto-confirm, false = needs approval\n  isActive        Boolean  @default(true) // admin can disable an account\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  bookings          Booking[]          @relation(\"UserBookings\")\n  recurringBookings RecurringBooking[] @relation(\"UserRecurringBookings\")\n  reviewedBookings  Booking[]          @relation(\"ReviewedByAdmin\")\n\n  @@index([role])\n}\n\n// ---------------------------\n// Field (playground)\n// ---------------------------\n\nmodel Field {\n  id        String  @id @default(cuid())\n  name      String // e.g. \"Игрище 1\", \"Игрище 2\"\n  sortOrder Int     @default(0)\n  isActive  Boolean @default(true)\n\n  bookings          Booking[]\n  recurringBookings RecurringBooking[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// ---------------------------\n// Booking (a single concrete 60-minute slot)\n// One row per field per date per hour — this is the source of truth\n// for availability checks, whether created standalone or generated\n// from a RecurringBooking.\n// ---------------------------\n\nmodel Booking {\n  id String @id @default(cuid())\n\n  fieldId String\n  field   Field  @relation(fields: [fieldId], references: [id])\n\n  date      DateTime @db.Date // calendar date of the match\n  startTime DateTime // full timestamp, always on the hour\n  endTime   DateTime // startTime + 60 min, stored for query convenience\n\n  status BookingStatus @default(PENDING)\n  source BookingSource\n\n  // Booker can be a registered user OR a guest (phone booking, no account)\n  userId     String?\n  user       User?   @relation(\"UserBookings\", fields: [userId], references: [id])\n  guestName  String?\n  guestPhone String?\n\n  // Optional team names entered at booking time\n  teamAName String?\n  teamBName String?\n\n  notes String? // free text, e.g. admin notes from the phone call\n\n  // Link back to the recurring series, if this booking was generated from one\n  recurringBookingId   String?\n  recurringBooking     RecurringBooking? @relation(fields: [recurringBookingId], references: [id])\n  isRecurrenceOverride Boolean           @default(false) // true if a single occurrence was edited/cancelled independently of the series\n\n  // Approval audit trail\n  reviewedByAdminId String?\n  reviewedByAdmin   User?     @relation(\"ReviewedByAdmin\", fields: [reviewedByAdminId], references: [id])\n  reviewedAt        DateTime?\n  rejectionReason   String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Prevents double-booking the same field/slot with an active (non-cancelled/rejected) booking.\n  // Enforced at the application layer (partial unique index recommended via raw SQL migration,\n  // since Prisma doesn't support partial unique constraints natively):\n  //   CREATE UNIQUE INDEX booking_field_slot_active_unique\n  //   ON \"Booking\" (\"fieldId\", \"startTime\")\n  //   WHERE status IN ('PENDING', 'CONFIRMED');\n  @@index([fieldId, date])\n  @@index([startTime])\n  @@index([userId])\n  @@index([status])\n}\n\n// ---------------------------\n// RecurringBooking (the \"template\" / series definition)\n// Generates Booking rows up to the global horizon via a scheduled job.\n// ---------------------------\n\nmodel RecurringBooking {\n  id String @id @default(cuid())\n\n  fieldId String\n  field   Field  @relation(fields: [fieldId], references: [id])\n\n  userId     String?\n  user       User?   @relation(\"UserRecurringBookings\", fields: [userId], references: [id])\n  guestName  String?\n  guestPhone String?\n\n  dayOfWeek Int // 0 = Sunday .. 6 = Saturday\n  startHour Int // 0-23, slot is always :00-:00, 60 minutes\n\n  teamAName String?\n  teamBName String?\n\n  frequency RecurrenceFrequency @default(WEEKLY)\n\n  startDate DateTime  @db.Date // first occurrence date\n  endDate   DateTime? @db.Date // optional end of series; null = indefinite (bounded by horizon setting)\n\n  isActive Boolean @default(true) // admin can deactivate the whole series\n\n  generatedBookings Booking[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([fieldId, dayOfWeek])\n  @@index([isActive])\n}\n\n// ---------------------------\n// AppSettings (singleton row) — global configuration\n// ---------------------------\n\nmodel AppSettings {\n  id                 String @id @default(\"singleton\")\n  bookingHorizonDays Int    @default(14) // how far ahead slots can be seen/booked\n\n  // Default display window (can still book outside these hours on request)\n  weekdayDisplayStartHour Int @default(17)\n  weekdayDisplayEndHour   Int @default(22)\n  weekendDisplayStartHour Int @default(9)\n  weekendDisplayEndHour   Int @default(23)\n\n  conflictCheckDaysAhead Int @default(7) // how far ahead to flag recurring-booking conflicts\n\n  updatedAt DateTime @updatedAt\n}\n\n// ---------------------------\n// Notification log (optional, for debugging/audit of emails sent)\n// ---------------------------\n\nmodel NotificationLog {\n  id        String   @id @default(cuid())\n  type      String // e.g. \"BOOKING_CONFIRMED\", \"BOOKING_PENDING\", \"RECURRENCE_CONFLICT\"\n  recipient String // email address\n  bookingId String?\n  payload   Json?\n  sentAt    DateTime @default(now())\n  success   Boolean  @default(true)\n  error     String?\n}\n",
